  4	// TodoInput manages only local input state and delegates todo creation
  5	// to its parent via the onAddTodo callback.
  6	function TodoInput({ onAddTodo }) {
  7	  const [text, setText] = useState('');
  8	  const [priority, setPriority] = useState('medium');
  9	  const [dueDate, setDueDate] = useState('');
 10	  const inputRef = useRef(null);
 11	  const isEmpty = text.trim().length === 0; // controls disabled state of the Add button
 12	
 13	  useEffect(() => {
 14	    if (inputRef.current) {
 15	      inputRef.current.focus();
 16	    }
 17	  }, []);
 18	
 19	  const submitCurrentText = () => {
 20	    const trimmed = text.trim();
 21	    if (!trimmed) return;
 22	
 23	    // Allow submitting an existing overdue date (e.g., from manual edit),
 24	    // but prevent creating a *new* todo with an overdue dueDate.
 25	    const normalizedDueDate = dueDate || null;
 26	    const safeDueDate = normalizedDueDate && isOverdue(normalizedDueDate) ? null : normalizedDueDate;
 27	
 28	    if (typeof onAddTodo === 'function') {
 29	      onAddTodo(trimmed, priority, safeDueDate);
 30	    }
 31	    setText('');
 32	    setPriority('medium');
 33	    setDueDate('');
 34	    if (inputRef.current) {
 35	      inputRef.current.focus();
 36	    }
 37	  };
 38	
 39	  const handleSubmit = (event) => {
 40	    event.preventDefault();
 41	    submitCurrentText();
 42	  };
 43	
 44	  const handleKeyDown = (event) => {
 45	    if (event.key === 'Escape') {
 46	      event.preventDefault();
 47	      setText('');
 48	      return;
 49	    }
 50	
 51	    if ((event.ctrlKey || event.metaKey) && event.key === 'Enter') {
 52	      event.preventDefault();
 53	      submitCurrentText();
 54	    }
 55	  };
 56	
 57	  return (
 58	    <form className="todo-input" onSubmit={handleSubmit}>
 59	      <label className="visually-hidden" htmlFor="new-todo-input">
 60	        Add a new todo
 61	      </label>
 62	      <input
 63	        id="new-todo-input"
 64	        type="text"
 65	        className="todo-input-field"
 66	        placeholder="What needs to be done?"
 67	        value={text}
 68	        onChange={(e) => setText(e.target.value)}
 69	        onKeyDown={handleKeyDown}
 70	        ref={inputRef}
 71	      />
 72	      <label className="visually-hidden" htmlFor="todo-priority-select">
 73	        Todo priority
 74	      </label>
 75	      <select
 76	        id="todo-priority-select"
 77	        className="priority-select"
 78	        value={priority}
 79	        onChange={(e) => setPriority(e.target.value)}
 80	      >
 81	        <option value="low">Low</option>
 82	        <option value="medium">Medium</option>
 83	        <option value="high">High</option>
 84	      </select>
 85	      <label className="visually-hidden" htmlFor="todo-due-date-input">
 86	        Due date (optional)
 87	      </label>
 88	      <input
 89	        id="todo-due-date-input"
 90	        type="date"
 91	        className="due-date-input"
 92	        value={dueDate}
 93	        onChange={(e) => setDueDate(e.target.value)}
 94	        min={getTodayString()}
 95	      />
 96	      <button type="submit" className="add-button" disabled={isEmpty}>
 97	        Add
 98	      </button>
 99	    </form>
100	  );
101	}
102	
103	export default TodoInput;

